arguments.command:
$headers = @{ Authorization = "Bearer $($env:SUPABASE_SERVICE_ROLE_KEY)" }
$u = "$($env:SUPABASE_URL)/rest/v1/agents?select=agent_id,last_heartbeat_at&limit=1"
try { Invoke-RestMethod -Method Get -Uri $u -Headers $headers | ConvertTo-Json -Depth 5 } catch { $_.Exception.Response.GetResponseStream() | % { $r = New-Object System.IO.StreamReader($_); $r.ReadToEnd() } }

$headers = @{ Authorization = "Bearer $($env:SUPABASE_SERVICE_ROLE_KEY)" }
$u = "$($env:SUPABASE_URL)/rest/v1/agents?select=agent_id,last_heartbeat_at&limit=3"
try {
  $resp = Invoke-WebRequest -Method Get -Uri $u -Headers $headers
  "STATUS=$($resp.StatusCode)"
  $resp.Content
} catch {
  "ERR"
  if ($_.Exception.Response) { $sr = New-Object IO.StreamReader($_.Exception.Response.GetResponseStream()); $sr.ReadToEnd() }
  else { $_ | Out-String }
}

